   460→    public static void writeHeader(ByteBuffer buffer,
   461→                                   long baseOffset,
   462→                                   int lastOffsetDelta,
   463→                                   int sizeInBytes,
   464→                                   byte magic,
   465→                                   CompressionType compressionType,
   466→                                   TimestampType timestampType,
   467→                                   long baseTimestamp,
   468→                                   long maxTimestamp,
   469→                                   long producerId,
   470→                                   short epoch,
   471→                                   int sequence,
   472→                                   boolean isTransactional,
   473→                                   boolean isControlBatch,
   474→                                   boolean isDeleteHorizonSet,
   475→                                   int partitionLeaderEpoch,
   476→                                   int numRecords) {
   477→        if (magic < RecordBatch.CURRENT_MAGIC_VALUE)
   478→            throw new IllegalArgumentException("Invalid magic value " + magic);
   479→        if (baseTimestamp < 0 && baseTimestamp != NO_TIMESTAMP)
   480→            throw new IllegalArgumentException("Invalid message timestamp " + baseTimestamp);
   481→
   482→        short attributes = computeAttributes(compressionType, timestampType, isTransactional, isControlBatch, isDeleteHorizonSet);
   483→
   484→        int position = buffer.position();
   485→        buffer.putLong(position + BASE_OFFSET_OFFSET, baseOffset);
   486→        buffer.putInt(position + LENGTH_OFFSET, sizeInBytes - LOG_OVERHEAD);
   487→        buffer.putInt(position + PARTITION_LEADER_EPOCH_OFFSET, partitionLeaderEpoch);
   488→        buffer.put(position + MAGIC_OFFSET, magic);
   489→        buffer.putShort(position + ATTRIBUTES_OFFSET, attributes);
   490→        buffer.putLong(position + BASE_TIMESTAMP_OFFSET, baseTimestamp);
   491→        buffer.putLong(position + MAX_TIMESTAMP_OFFSET, maxTimestamp);
   492→        buffer.putInt(position + LAST_OFFSET_DELTA_OFFSET, lastOffsetDelta);
   493→        buffer.putLong(position + PRODUCER_ID_OFFSET, producerId);
   494→        buffer.putShort(position + PRODUCER_EPOCH_OFFSET, epoch);
   495→        buffer.putInt(position + BASE_SEQUENCE_OFFSET, sequence);
   496→        buffer.putInt(position + RECORDS_COUNT_OFFSET, numRecords);
   497→        long crc = Crc32C.compute(buffer, ATTRIBUTES_OFFSET, sizeInBytes - ATTRIBUTES_OFFSET);
   498→        buffer.putInt(position + CRC_OFFSET, (int) crc);
   499→        buffer.position(position + RECORD_BATCH_OVERHEAD);
